a = input()
num = 0
ans = 0
b = {"S": 1200, "s": 508, "L": 157000, "G": 1000, "E": 12200, "H": 469, "B": 337, "k": 10}
for i in range(len(a)):
    if a[i] in b:
        ans += b[a[i]] * num
        num = 0
    else:
        num *= 10
        num += int(a[i])
print(ans)
